<template>
	<view class="container">
		<view class="header">
			<text class="title">报表分析</text>
		</view>
		
		<view class="report-tabs">
			<text class="tab-item" :class="{ active: activeTab === 'production' }" @click="activeTab = 'production'">生产报表</text>
			<text class="tab-item" :class="{ active: activeTab === 'quality' }" @click="activeTab = 'quality'">质量报表</text>
			<text class="tab-item" :class="{ active: activeTab === 'inventory' }" @click="activeTab = 'inventory'">库存报表</text>
		</view>
		
		<view class="report-content" v-if="activeTab === 'production'">
			<view class="chart-section">
				<text class="section-title">生产趋势</text>
				<view class="chart-placeholder">
					<text class="chart-text">生产趋势图表</text>
				</view>
			</view>
			
			<view class="data-section">
				<text class="section-title">生产数据</text>
				<view class="data-grid">
					<view class="data-item">
						<text class="data-label">本月产量</text>
						<text class="data-value">{{ monthlyProduction }}</text>
					</view>
					<view class="data-item">
						<text class="data-label">日均产量</text>
						<text class="data-value">{{ dailyAverage }}</text>
					</view>
					<view class="data-item">
						<text class="data-label">最大单日产量</text>
						<text class="data-value">{{ maxDailyProduction }}</text>
					</view>
					<view class="data-item">
						<text class="data-label">生产效率</text>
						<text class="data-value">{{ productionEfficiency }}%</text>
					</view>
				</view>
			</view>
		</view>
		
		<view class="report-content" v-if="activeTab === 'quality'">
			<view class="chart-section">
				<text class="section-title">质量分布</text>
				<view class="chart-placeholder">
					<text class="chart-text">质量分布图表</text>
				</view>
			</view>
			
			<view class="data-section">
				<text class="section-title">质量数据</text>
				<view class="data-grid">
					<view class="data-item">
						<text class="data-label">合格率</text>
						<text class="data-value">{{ qualityRate }}%</text>
					</view>
					<view class="data-item">
						<text class="data-label">不合格数</text>
						<text class="data-value">{{ rejectCount }}</text>
					</view>
					<view class="data-item">
						<text class="data-label">缺陷率</text>
						<text class="data-value">{{ defectRate }}%</text>
					</view>
					<view class="data-item">
						<text class="data-label">客户投诉</text>
						<text class="data-value">{{ customerComplaints }}</text>
					</view>
				</view>
			</view>
		</view>
		
		<view class="report-content" v-if="activeTab === 'inventory'">
			<view class="chart-section">
				<text class="section-title">库存变化</text>
				<view class="chart-placeholder">
					<text class="chart-text">库存变化图表</text>
				</view>
			</view>
			
			<view class="data-section">
				<text class="section-title">库存数据</text>
				<view class="data-grid">
					<view class="data-item">
						<text class="data-label">当前库存</text>
						<text class="data-value">{{ currentInventory }}</text>
					</view>
					<view class="data-item">
						<text class="data-label">库存周转</text>
						<text class="data-value">{{ inventoryTurnover }}天</text>
					</view>
					<view class="data-item">
						<text class="data-label">库存成本</text>
						<text class="data-value">¥{{ inventoryCost }}</text>
					</view>
					<view class="data-item">
						<text class="data-label">库存预警</text>
						<text class="data-value">{{ inventoryAlerts }}</text>
					</view>
				</view>
			</view>
		</view>
	</view>
</template>

<script>
export default {
	data() {
		return {
			activeTab: 'production',
			// 生产报表数据
			monthlyProduction: 12500,
			dailyAverage: 416,
			maxDailyProduction: 580,
			productionEfficiency: 92.5,
			// 质量报表数据
			qualityRate: 98.2,
			rejectCount: 225,
			defectRate: 1.8,
			customerComplaints: 5,
			// 库存报表数据
			currentInventory: 18500,
			inventoryTurnover: 18.5,
			inventoryCost: 258000,
			inventoryAlerts: 3
		};
	}
};
</script>

<style scoped>
.container {
	padding: 20rpx;
	background-color: #f5f5f5;
	min-height: 100vh;
}

.header {
	padding: 20rpx;
	background-color: #fff;
	border-radius: 10rpx;
	margin-bottom: 20rpx;
	box-shadow: 0 2rpx 10rpx rgba(0, 0, 0, 0.1);
}

.title {
	font-size: 36rpx;
	font-weight: bold;
	color: #333;
}

.report-tabs {
	display: flex;
	background-color: #fff;
	border-radius: 10rpx;
	padding: 10rpx;
	margin-bottom: 20rpx;
	box-shadow: 0 2rpx 10rpx rgba(0, 0, 0, 0.1);
}

.tab-item {
	flex: 1;
	text-align: center;
	padding: 15rpx;
	font-size: 28rpx;
	color: #666;
	border-radius: 8rpx;
	cursor: pointer;
	transition: all 0.3s;
}

.tab-item.active {
	background-color: #007aff;
	color: #fff;
}

.report-content {
	display: flex;
	flex-direction: column;
	gap: 20rpx;
}

.chart-section {
	background-color: #fff;
	border-radius: 10rpx;
	padding: 20rpx;
	box-shadow: 0 2rpx 10rpx rgba(0, 0, 0, 0.1);
}

.section-title {
	font-size: 32rpx;
	font-weight: bold;
	color: #333;
	margin-bottom: 15rpx;
}

.chart-placeholder {
	height: 250rpx;
	background-color: #f9f9f9;
	border-radius: 8rpx;
	display: flex;
	justify-content: center;
	align-items: center;
}

.chart-text {
	font-size: 24rpx;
	color: #8e8e93;
}

.data-section {
	background-color: #fff;
	border-radius: 10rpx;
	padding: 20rpx;
	box-shadow: 0 2rpx 10rpx rgba(0, 0, 0, 0.1);
}

.data-grid {
	display: grid;
	grid-template-columns: repeat(2, 1fr);
	gap: 20rpx;
}

.data-item {
	background-color: #f9f9f9;
	border-radius: 8rpx;
	padding: 20rpx;
	text-align: center;
}

.data-label {
	font-size: 24rpx;
	color: #666;
	margin-bottom: 10rpx;
}

.data-value {
	font-size: 48rpx;
	font-weight: bold;
	color: #007aff;
}
</style>